const req = $input.first().json;
return [{ json: {
  client_id: req.body.client_id,
  timestamp: req.headers['x-caiac-timestamp'],
  signature: req.headers['x-caiac-signature'],
  token: req.body.token
} }];

const session = $input.first().json;
if (!session || !session.user_id) throw new Error('Invalid or expired token');
return [{ json: session }];

function uuid() {
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, c => {
    const r = Math.random() * 16 | 0;
    return (c === 'x' ? r : (r & 0x3 | 0x8)).toString(16);
  });
}
return [{ json: { jti: uuid() } }];

return [{ json: {
  token: $('Reissue JWT').item.json.token,
  session_id: $('Check Token Valid').item.json.session_id,
  expires_at: new Date(Date.now() + 3600 * 1000).toISOString()
} }];
